mapper.select:
SELECT DISTINCT c.*
FROM conversations c
INNER JOIN conversation_members cm ON c.id = cm.conversation_id
WHERE cm.user_id = #{userId}
AND c.deleted_at IS NULL

    AND c.id > #{cursorId}

ORDER BY c.id ASC
LIMIT #{pageSize}

SELECT c.id, c.public_id AS publicId, c.type, c.name, c.latest_message_id AS latestMessageId, m.public_id AS latestMessagePublicId, m.content AS latestMessageContent, m.created_at AS latestMessageCreatedAt, (SELECT COUNT(*) FROM messages m2 WHERE m2.conversation_id = c.id AND m2.deleted_at IS NULL AND m2.sender_id != #{userId} AND m2.id > coalesce(cm.last_read_message_id, 0) ) AS unreadCount FROM conversations c INNER JOIN conversation_members cm ON c.id = cm.conversation_id LEFT JOIN messages m ON m.id = c.latest_message_id WHERE cm.user_id = #{userId} AND c.deleted_at IS NULL
AND COALESCE(c.latest_message_id, c.id) < #{cursorId}
ORDER BY COALESCE(c.latest_message_id, c.id) DESC LIMIT #{pageSize}

SELECT c.*
FROM conversations c
INNER JOIN conversation_members cm ON c.id = cm.conversation_id
WHERE cm.user_id = #{userId}
AND c.type = 'GROUP'
AND c.deleted_at IS NULL

    AND c.id > #{cursor}

ORDER BY c.id ASC
LIMIT #{limit}
